## Helper method
def helper(n):
    if n <= 1:
        return n
    return helper(n-1) + helper(n-2)

## function definition
def countNumberOfWays(s):
    return helper(s+1)

## Driver code
n = 10000000000
result = countNumberOfWays(n)
print("Number of ways to reach upstairs is",result)
